import 'dart:async'; import 'package:injectable/injectable.dart'; import '../../../core/utils/app_logger.dart'; @injectable class ConnectionWatchdog { Timer? _timer; int _missedBeats = 0; static const _maxMissed = 3; VoidCallback? _onTimeout; void start({required VoidCallback onTimeout}) { _onTimeout = onTimeout; _timer = Timer.periodic(const Duration(seconds: 30), (_) { _missedBeats++; if (_missedBeats >= _maxMissed) { AppLogger.warning('Watchdog: connection timeout'); onTimeout(); reset(); } }); } void heartbeat() => _missedBeats = 0; void reset() { _timer?.cancel(); _missedBeats = 0; } void dispose() => _timer?.cancel(); }